// assets/vendor/franc-all.min.js
// Local ESM bridge -> exposes window.franc / window.francAll (offline, no CDN)

import * as mod from "./index.js";

(function () {
  try {
    // Most builds expose { franc, francAll }
    const franc = mod.franc || mod.default || null;
    const francAll = mod.francAll || null;

    if (typeof franc === "function") window.franc = franc;
    if (typeof francAll === "function") window.francAll = francAll;

    // Optional: tiny sanity flag
    window.__FRANC_READY__ = {
      ok: typeof window.franc === "function",
      hasFrancAll: typeof window.francAll === "function"
    };
  } catch (e) {
    window.__FRANC_READY__ = { ok: false, error: String(e && (e.message || e)) };
  }
})();
